prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?normId ?origId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  FILTER(CONTAINS(STR(?model), "1ad939eef40c461dafae27f75a0586d3") || CONTAINS(STR(?normId), "1ad939eef40c461dafae27f75a0586d3") || CONTAINS(STR(?origId), "1ad939eef40c461dafae27f75a0586d3"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName ?startEvent ?startName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  ?defs tai:belongsTo ?model .
  ?defs a bboExt:Definitions .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
  OPTIONAL {
    ?startEvent a bboExt:StartEvent .
    ?startEvent tai:belongsTo ?choreo .
    OPTIONAL { ?startEvent bbo:name ?startName . }
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?node ?nodeName ?nodeType WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  ?defs tai:belongsTo ?model .
  ?defs a bboExt:Definitions .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .

  # All flow nodes (tasks, events, gateways)
  { ?node a bboExt:ChoreographyTask . }
  UNION { ?node a bboExt:StartEvent . }
  UNION { ?node a bboExt:EndEvent . }
  UNION { ?node a bboExt:IntermediateCatchEvent . }
  UNION { ?node a bboExt:ExclusiveGateway . }
  UNION { ?node a bboExt:ParallelGateway . }
  UNION { ?node a bboExt:EventBasedGateway . }

  ?node tai:belongsTo ?choreo .
  OPTIONAL { ?node bbo:name ?nodeName . }
  OPTIONAL { ?node a ?nodeType . }

  # Exclude nodes that are reachable from start event
  FILTER NOT EXISTS {
    ?startEvent a bboExt:StartEvent .
    ?startEvent tai:belongsTo ?choreo .
    ?startEvent ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?node .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?nodeType (COUNT(*) as ?count) WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  ?defs tai:belongsTo ?model .
  ?defs a bboExt:Definitions .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .

  { ?node a bboExt:ChoreographyTask . }
  UNION { ?node a bboExt:StartEvent . }
  UNION { ?node a bboExt:EndEvent . }
  UNION { ?node a bboExt:IntermediateCatchEvent . }
  UNION { ?node a bboExt:ExclusiveGateway . }
  UNION { ?node a bboExt:ParallelGateway . }
  UNION { ?node a bboExt:EventBasedGateway . }

  ?node tai:belongsTo ?choreo .
  ?node a ?nodeType .
}
GROUP BY ?nodeType
ORDER BY DESC(?count)
